events.success:
function successCallback( res) {
    if (res.data && res.data.data) {
        $this.utils.notification.succeee.success({
            title: '成功',
            content: '更新用户成功',
        })
    } else {
        $this.utils.notification.succeee.error({
            title: '失败',
            content: '更新用户失败',
        })
    }
}

events.fail:
function failCallback() {
    $this.utils.notification.succeee.error({
        title: '失败',
        content: '更新用户失败',
    })
}

